//! Halo2 implementation for the RISC-V RV32IM Execution Trace
//!
//! Maps the ExecutionStep trace generated by our `execution-engine` into 
//! a strict Plonkish Arithmetization (AIR) using the Halo2 zero-knowledge framework.

use halo2_proofs::{
    arithmetic::FieldExt,
    circuit::{Layouter, SimpleFloorPlanner, Value},
    plonk::{Advice, Circuit, Column, ConstraintSystem, Error, Selector, Instance},
    poly::Rotation,
};
use halo2curves::bn256::Fr as Fp; // BN254 Scalar Field

/// Given the 32-bit registers from the RV32IM trace, we construct a table.
#[derive(Clone, Debug)]
pub struct RiscVConfig {
    pub pc: Column<Advice>,
    pub instruction: Column<Advice>,
    pub registers: [Column<Advice>; 32], // Simulating the 32 GP registers
    
    // Selectors to toggle constraints based on the instruction type
    pub s_add: Selector,
    pub s_mul: Selector,
}

impl RiscVConfig {
    pub fn configure<F: FieldExt>(meta: &mut ConstraintSystem<F>) -> Self {
        let pc = meta.advice_column();
        let instruction = meta.advice_column();
        
        let mut registers = vec![];
        for _ in 0..32 {
            registers.push(meta.advice_column());
        }
        let registers: [Column<Advice>; 32] = registers.try_into().unwrap();

        let s_add = meta.selector();
        let s_mul = meta.selector();

        // Enforce state transition constraints
        meta.create_gate("RV32IM ALU Addition", |meta| {
            let s = meta.query_selector(s_add);
            // Simplifying: Assume instruction encodes rd, rs1, rs2 logic directly into columns
            // rd_next = rs1_curr + rs2_curr
            let rs1 = meta.query_advice(registers[1], Rotation::cur()); // Mock Register 1
            let rs2 = meta.query_advice(registers[2], Rotation::cur()); // Mock Register 2
            let rd = meta.query_advice(registers[3], Rotation::next()); // Mock destination Register 3 in next state
            
            vec![s * (rs1 + rs2 - rd)]
        });

        Self {
            pc,
            instruction,
            registers,
            s_add,
            s_mul,
        }
    }
}

/// The Halo2 Circuit implementation that takes our external ExecutionTrace
#[derive(Default)]
pub struct ZkVmCircuit<F: FieldExt> {
    pub pc_trace: Vec<Value<F>>,
    pub register_trace: Vec<[Value<F>; 32]>,
}

impl<F: FieldExt> Circuit<F> for ZkVmCircuit<F> {
    type Config = RiscVConfig;
    type FloorPlanner = SimpleFloorPlanner;

    fn without_witnesses(&self) -> Self {
        Self::default()
    }

    fn configure(meta: &mut ConstraintSystem<F>) -> Self::Config {
        RiscVConfig::configure(meta)
    }

    fn synthesize(
        &self,
        config: Self::Config,
        mut layouter: impl Layouter<F>,
    ) -> Result<(), Error> {
        layouter.assign_region(
            || "RV32IM Execution Trace",
            |mut region| {
                for (offset, reg_state) in self.register_trace.iter().enumerate() {
                    // Assign PC
                    region.assign_advice(|| "pc", config.pc, offset, || self.pc_trace[offset])?;
                    
                    // Assign Registers
                    for i in 0..32 {
                        region.assign_advice(|| format!("x{}", i), config.registers[i], offset, || reg_state[i])?;
                    }

                    // Enable relevant Selectors (Simplification for mock)
                    if offset % 2 == 0 {
                        config.s_add.enable(&mut region, offset)?;
                    } else {
                        config.s_mul.enable(&mut region, offset)?;
                    }
                }
                Ok(())
            },
        )?;
        Ok(())
    }
}

